messages.content:
你是 marketting-planning-intent 项目的 attribute agent。
只归因当前单轮 intent-recognition 链路：request_normalization、intent_api_call、adapter_extraction、label_mapping；不要把 planning/SSE generation 的问题归入本项目。
优先使用 intent_contract_probe 定位 intent label、required slots/entities、confidence threshold、fallback policy 或 label_mapping 的当前证据差异。
只能输出 AttributeResult JSON 所需字段；证据不足时用 evidence_strength=none/weak 和 root_cause_hypothesis 表达缺口。
最终只输出 AttributeResult JSON 所需字段：expectation_attributions、suspected_locations、root_cause_hypothesis、evidence、evidence_strength。

## 输出约束：attribute 归因分析输出
你的输出必须是合法 JSON，且严格符合以下 JSON Schema：
```json
{
  "type": "object",
  "properties": {
    "expectation_attributions": {
      "type": "array",
      "items": {
        "$ref": "#/$defs/ExpectationAttribution"
      },
      "minItems": 1
    },
    "suspected_locations": {
      "type": "array",
      "items": {}
    },
    "root_cause_hypothesis": {
      "type": "string",
      "minLength": 1
    },
    "evidence": {
      "type": "array",
      "items": {}
    },
    "evidence_strength": {
      "type": "string",
      "minLength": 1
    }
  },
  "additionalProperties": false,
  "$defs": {
    "ExpectationAttribution": {
      "type": "object",
      "properties": {
        "expectation_id": {
          "type": "string",
          "minLength": 1
        },
        "fulfillment_status": {
          "type": "string",
          "minLength": 1
        },
        "suspected_locations": {
          "type": "array",
          "items": {}
        },
        "root_cause_hypothesis": {
          "type": "string",
          "minLength": 1
        },
        "evidence": {
          "type": "array",
          "items": {}
        }
      },
      "additionalProperties": false,
      "required": [
        "expectation_id",
        "fulfillment_status"
      ]
    }
  },
  "required": [
    "expectation_attributions",
    "root_cause_hypothesis"
  ]
}
```

### 强约束
- 最终回答必须只包含一个 JSON object；不要输出 Markdown，不要使用 ```json 代码块，不要在 JSON 外输出解释、前缀或后缀。
- 最终回答首字符必须是 `{`，末字符必须是 `}`。
- JSON 字符串内部如需引用用户原词，禁止直接写未转义英文双引号；请使用中文引号“”或转义为 `\"`。
- 必须包含 `required` 列表中的所有字段。
- 每个字段值必须匹配 schema 中的类型。
- 以下字段必须非空（空字符串/空数组/空对象/None 均视为不合规，会被阻断）：['expectation_attributions', 'root_cause_hypothesis']
- `additionalProperties: false`：禁止输出 schema 未定义的字段。
- 禁止把 schema 里的类型描述符（如 "string"）原样当作内容填进去——每个字段必须填入真实内容。

{
  "expectation_attributions": [
    {
      "expectation_id": "意图标签识别为customer_portrait",
      "fulfillment_status": "not_fulfilled",
      "suspected_locations": [
        "adapter_extraction",
        "label_mapping"
      ],
      "root_cause_hypothesis": "adapter_extraction 输出 'other'，导致标签未能映射为期望的 customer_portrait",
      "evidence": [
        {
          "source": "extracted_output",
          "key": "intent",
          "value": "other"
        },
        {
          "source": "intent_evidence",
          "key": "raw_intent",
          "value": "4001"
        }
      ]
    },
    {
      "expectation_id": "目标实体提取为重疾险",
      "fulfillment_status": "not_fulfilled",
      "suspected_locations": [
        "adapter_extraction",
        "intent_api_call"
      ],
      "root_cause_hypothesis": "意图识别失败导致实体提取未触发，target_value 为 null，无法输出“重疾险”",
      "evidence": [
        {
          "source": "extracted_output",
          "key": "target_value",
          "value": null
        }
      ]
    },
    {
      "expectation_id": "置信度达到0.95或以上",
      "fulfillment_status": "not_fulfilled",
      "suspected_locations": [
        "adapter_extraction"
      ],
      "root_cause_hypothesis": "意图解析错误导致置信度评估仅 0.5，远低于要求的 0.95",
      "evidence": [
        {
          "source": "extracted_output",
          "key": "confidence",
          "value": 0.5
        }
      ]
    },
    {
      "expectation_id": "避免回退为other意图",
      "fulfillment_status": "not_fulfilled",
      "suspected_locations": [
        "adapter_extraction",
        "label_mapping"
      ],
      "root_cause_hypothesis": "意图解析链路最终输出 'other'，直接触发了兜底逻辑而非期望的业务意图",
      "evidence": [
        {
          "source": "extracted_output",
          "key": "intent",
          "value": "other"
        },
        {
          "source": "runtime_checks",
          "key": "actual_mapping",
          "value": "other"
        }
      ]
    },
    {
      "expectation_id": "intent_contract",
      "fulfillment_status": "not_fulfilled",
      "suspected_locations": [
        "整体意图识别链路"
      ],
      "root_cause_hypothesis": "当前单轮意图识别未满足 reference contract：期望 intent=customer_portrait，实际为 other，置信度 0.5",
      "evidence": [
        {
          "source": "judge_result",
          "status": "not_fulfilled",
          "reason": "intent_contract not fulfilled"
        }
      ]
    }
  ],
  "suspected_locations": [
    {
      "stage": "adapter_extraction",
      "issue": "从 API 响应中提取 intent 时出错，返回 'other' 且未正确传递 raw_intent"
    },
    {
      "stage": "label_mapping",
      "issue": "在 raw_intent 缺失（实际为 None）时默认映射为 'other'，未能命中 customer_portrait 映射"
    },
    {
      "stage": "intent_api_call",
      "issue": "API 响应格式可能与 adapter 预期不符，导致解析丢失原始意图编码"
    }
  ],
  "root_cause_hypothesis": "在 intent_api_call 返回有效意图编码 '4001' 的情况下，adapter_extraction 未能正确解析该编码，导致 raw_intent 丢失（变为 None），并通过 label_mapping 降级为兜底意图 'other'。这直接导致了意图标签错误、实体缺失、置信度低下以及回退至 other 意图等一系列失败。",
  "evidence": [
    {
      "source": "extracted_output",
      "data": {
        "intent": "other",
        "confidence": 0.5,
        "target_value": null
      }
    },
    {
      "source": "intent_evidence",
      "data": {
        "raw_intent": "4001",
        "slots": {},
        "entities": [],
        "ambiguous": false,
        "fallback": false
      }
    },
    {
      "source": "runtime_checks",
      "summary": "raw_intent=None 经项目映射得到 other",
      "root_cause": "label_mapping"
    },
    {
      "source": "adapter_extraction_stage",
      "evidence": {
        "intent": "other",
        "confidence": 0.5
      }
    },
    {
      "source": "label_mapping_stage",
      "evidence": {
        "intent": "other"
      }
    }
  ],
  "evidence_strength": "high"
}

